import{c as a,Q as i,j as e,m as n}from"./chunks/framework.iD28w_5a.js";const g=JSON.parse('{"title":"022-ring3-usermode-2 · 用户态 (Ring 3)","description":"","frontmatter":{"title":"022-ring3-usermode-2 · 用户态 (Ring 3)"},"headers":[],"relativePath":"tutorial/022-ring3-usermode-2.md","filePath":"tutorial/022-ring3-usermode-2.md","lastUpdated":1779686691000}'),t={name:"tutorial/022-ring3-usermode-2.md"};function l(p,s,r,h,d,k){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="踩坑实录-三个让-ring-3-起不来的致命-bug" tabindex="-1">踩坑实录：三个让 Ring 3 起不来的致命 Bug <a class="header-anchor" href="#踩坑实录-三个让-ring-3-起不来的致命-bug" aria-label="Permalink to &quot;踩坑实录：三个让 Ring 3 起不来的致命 Bug&quot;">​</a></h1><blockquote><p>标签：debug、Triple Fault、页表权限、identity mapping、MSR、wrmsr 前置：<a href="./022-ring3-usermode-1">022-1 从 Ring 0 到 Ring 3</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>如果你跟着我们一路从 tag 000 写到了 tag 021，大概已经习惯了&quot;写代码、编译、运行、看到预期输出&quot;的节奏。但 tag 022 不是这样的——这个 tag 的开发过程可以用四个字来形容：血泪交加。我从写下 <code>jump_to_usermode()</code> 的第一行代码到最终看到 <code>CS=0x33, #GP at RIP=0x400000 from user mode (Ring 3)</code> 这行输出，中间经历了整整三天、三个独立 bug、无数次的 Triple Fault 和串口乱码。</p><p>这三个 bug 各自独立，每一个都足以让 Ring 3 完全起不来，而且它们之间会互相掩盖——修了 Bug 1 才能看到 Bug 2 的真实表现，修了 Bug 2 才能暴露 Bug 3。所以这篇文章不光是&quot;踩坑记录&quot;，更是一份 Ring 3 调试方法论。如果你也在写自己的 OS 内核、也在尝试进入 Ring 3，我希望这篇文章能帮你省下三天时间。</p><h2 id="bug-排查路线图" tabindex="-1">Bug 排查路线图 <a class="header-anchor" href="#bug-排查路线图" aria-label="Permalink to &quot;Bug 排查路线图&quot;">​</a></h2><p>在进入具体分析之前，先给一张&quot;Ring 3 起不来&quot;的排查路线图：</p><table tabindex="0"><thead><tr><th>现象</th><th>第一个检查</th><th>第二个检查</th><th>可能的 bug</th></tr></thead><tbody><tr><td>串口输出乱码（<code>[</code>）</td><td>PDPT identity mapping</td><td>demand-page 重入</td><td>Bug 1: FB mapping 丢失</td></tr><tr><td>CS 异常（非 0x33）</td><td>STAR MSR EDX 值</td><td>shlq 移位量</td><td>Bug 2: wrmsr 只写 EDX</td></tr><tr><td>#PF error_code=0x05</td><td>每级页表 bit 2</td><td>walk_level user_flag</td><td>Bug 3: 缺 FLAG_USER</td></tr><tr><td>SYSRET 后 #UD</td><td>EFER.SCE 位</td><td>rdmsr 验证</td><td>SCE 未启用</td></tr><tr><td>Triple Fault</td><td>TSS.RSP0</td><td>ltr 是否执行</td><td>RSP0 未设或无效</td></tr></tbody></table><p>注意：这张表假设你已经正确设置了 GDT 用户段描述符（tag 010）和 AddressSpace（tag 018）。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>调试环境：QEMU 8.x，KVM 加速（宿主机 Linux 6.x，x86-64），串口输出到 stdio。调试手段主要是串口 kprintf（因为 GDB 在特权级切换时的行为不太可靠），以及偶尔通过 QEMU Monitor 检查寄存器状态。</p><p>如果你正在调试自己的内核，建议优先使用 <code>-accel tcg -cpu max</code> 模式排除 KVM 干扰，再回到 KVM 模式验证性能。</p><h2 id="bug-1-framebuffer-identity-mapping-丢失" tabindex="-1">Bug 1：Framebuffer Identity Mapping 丢失 <a class="header-anchor" href="#bug-1-framebuffer-identity-mapping-丢失" aria-label="Permalink to &quot;Bug 1：Framebuffer Identity Mapping 丢失&quot;">​</a></h2><h3 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p><code>launch_first_user()</code> 执行后，串口输出变成这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[USER] Setting up first user-mode program...</span></span>
<span class="line"><span>[[[[[[[[[[[[[[[[VMM] Demand-paged 0x00000000FD08F000 -&gt; phys 0x0000000001089000</span></span>
<span class="line"><span>V[[[[[[[[[[[[[</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>满屏的 <code>[</code> 字符，夹杂着 VMM 的 demand-page 日志。这显然不是我们想看到的东西。</p><h3 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>我们的 framebuffer 使用 identity mapping——物理地址直接当虚拟地址用，通过 PDPT[3] 的 1GB 大页映射在内核页表中。但 <code>AddressSpace</code> 构造时只复制 PML4 高半区条目（256-511），低半区全部清零。虽然 PML4[0] 本身会被复制（因为内核 PML4[0] 有指向 identity mapping PDPT 的条目），但新的 PDPT 是空的——1GB 大页映射丢失了。</p><p>当 SYSRET 进入 Ring 3 后，CR3 指向用户地址空间。此时 kprintf 写 framebuffer，MMU 查找 0xFD000000（framebuffer 的 identity mapping 地址），发现 PDPT[3] 是空的，触发 #PF。Demand-page handler 以为这是一个普通的不存在页，分配了一个新的物理页映射到这个地址。但这个物理页是普通 RAM，不是 MMIO——写入无效地址。更严重的是，page fault handler 内部又调用了 kprintf（打印 demand-page 日志），形成重入——kprintf 再次写 framebuffer，再次 #PF，再次 demand-page... 串口输出就被这些重入调用搞成了满屏方括号。</p><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><p>在 <code>launch_first_user()</code> 中，activate() 之前把内核 PDPT 中已有的 identity mapping 条目复制到用户 PDPT：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kern_pdpt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;const</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint64_t*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    (kern_pml4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADDR_MASK) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KERNEL_VMA);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_pdpt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;uint64_t*&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    (user_pml4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADDR_MASK) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KERNEL_VMA);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint32_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PT_ENTRIES; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ((kern_pdpt[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_PRESENT) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user_pdpt[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_PRESENT)) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        user_pdpt[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kern_pdpt[i];</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>只复制&quot;内核有但用户没有&quot;的条目，避免覆盖已有的用户映射。这段代码解决了 identity mapping 丢失的问题——切换 CR3 后 framebuffer 仍然可用，kprintf 不再触发 #PF 重入。</p><h3 id="教训" tabindex="-1">教训 <a class="header-anchor" href="#教训" aria-label="Permalink to &quot;教训&quot;">​</a></h3><p>这个 bug 的根本原因是 identity mapping 和地址空间隔离之间的矛盾。Identity mapping 把物理地址直接当虚拟地址用（在低半区），而地址空间隔离要求用户空间有自己的低半区页表。在&quot;切换 CR3&quot;这个操作中，所有低半区的映射都会丢失，除非显式复制。更好的方案是把 framebuffer 映射到高半区（像内核代码一样），这样 AddressSpace 构造时自动复制高半区条目就不需要额外处理了。但这是一个更大的重构，我们先用&quot;复制 PDPT 条目&quot;这个权宜之计。</p><h2 id="bug-2-star-msr-shlq-位数错误" tabindex="-1">Bug 2：STAR MSR shlq 位数错误 <a class="header-anchor" href="#bug-2-star-msr-shlq-位数错误" aria-label="Permalink to &quot;Bug 2：STAR MSR shlq 位数错误&quot;">​</a></h2><h3 id="现象-1" tabindex="-1">现象 <a class="header-anchor" href="#现象-1" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p>修了 Bug 1 后，串口不再乱码了，但 SYSRET 后 CS 寄存器变成了 0x10（内核代码段）而不是 0x33。CPU 没有切换到 Ring 3——它还在内核代码段上跑，特权级没变，接下来的行为取决于内存中 0x400000 地址处的内核映射内容。</p><h3 id="根因-1" tabindex="-1">根因 <a class="header-anchor" href="#根因-1" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>这完全是 <code>wrmsr</code> 指令语义的锅。MSR 寄存器宽 64 位，但 <code>wrmsr</code> 指令只写 EDX:EAX——EDX 写入 MSR 的高 32 位，EAX 写入低 32 位。注意是 EDX 和 EAX（32 位寄存器），不是 RDX 和 RAX（64 位寄存器）。</p><p>我们的原始代码是这样写的：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $0x23, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdx</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">shlq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 期望把 0x23 移到 bit 63-32</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">orq  $0x10, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>shlq $32</code> 确实把 0x23 移到了 RDX 的 bit 39-32，所以 RDX = 0x0000002300000010。但 <code>wrmsr</code> 只读 EDX（bit 31-0），所以写入 STAR 高 32 位的值是 EDX = 0x00000010。STAR[63:48] = 0 而不是 0x23，SYSRET 计算出 CS = 0+16 = 0x10（内核代码段），CPU 不会切换到 Ring 3。</p><h3 id="修复-1" tabindex="-1">修复 <a class="header-anchor" href="#修复-1" aria-label="Permalink to &quot;修复&quot;">​</a></h3><p>把移位量从 $32 改为 $16：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $0x23, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdx</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">shlq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # EDX[31:16] = 0x23 -&gt; STAR[63:48]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">orq  $0x10, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # EDX[15:0]  = 0x10 -&gt; STAR[47:32]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>shlq $16</code> 后 EDX = 0x00230010，<code>wrmsr</code> 把这个值写入 STAR 高 32 位，STAR[63:48] = 0x23，SYSRET 计算出 CS = 0x23+16 = 0x33（User64 代码段），SS = 0x23+8 = 0x2B（用户数据段）。正确了。</p><h3 id="教训-1" tabindex="-1">教训 <a class="header-anchor" href="#教训-1" aria-label="Permalink to &quot;教训&quot;">​</a></h3><p>x86 的 <code>wrmsr</code>/<code>rdmsr</code> 指令只操作 32 位寄存器（EDX:EAX），即使在 64 位模式下也是如此。如果你需要对 RDX 做移位操作来构造 MSR 值，一定要检查目标寄存器是 32 位的 EDX 还是 64 位的 RDX。这个 bug 的隐蔽之处在于它不会触发任何异常——只是静默地选择了错误的段选择子。</p><p><strong>如何避免这类 bug</strong>：写 MSR 后立即用 rdmsr 读回并打印验证。如果你在 usermode_init_asm 末尾加一段 rdmsr 读 STAR 并通过串口打印 EDX 的值，就能在开发阶段立即发现 EDX 是 0x00000008 而不是预期的 0x00080008。这种&quot;写后验证&quot;的习惯在 MSR 编程中非常重要。</p><h2 id="bug-3-walk-level-缺-flag-user" tabindex="-1">Bug 3：walk_level 缺 FLAG_USER <a class="header-anchor" href="#bug-3-walk-level-缺-flag-user" aria-label="Permalink to &quot;Bug 3：walk_level 缺 FLAG_USER&quot;">​</a></h2><h3 id="现象-2" tabindex="-1">现象 <a class="header-anchor" href="#现象-2" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p>修了 Bug 1 和 Bug 2 后，SYSRET 正确进入了 Ring 3（CS=0x33），但立刻触发 #PF：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>==== EXCEPTION: #PF (vector 14) ====</span></span>
<span class="line"><span>  ERROR CODE = 0x0000000000000005</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>error_code=0x05 意味着 P=1（页存在）、W/R=0（读操作）、U/S=1（Ring 3 用户态）。页存在但 Ring 3 没权限访问——典型的页表权限不足。</p><h3 id="根因-2" tabindex="-1">根因 <a class="header-anchor" href="#根因-2" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>x86-64 的四级页表权限检查机制非常严格：从 PML4 到 PT，每一级的页表项都必须设置 U/S 位（bit 2，即 FLAG_USER）。如果 PML4 条目没有 FLAG_USER，CPU 在 Ring 3 访问该虚拟地址时直接在第一级就被拒绝，即使后续的 PDPT/PD/PT 条目都有 FLAG_USER 也无济于事。</p><p>我们的 VMM 中，<code>walk_level</code> 函数在分配新的中间页表时只设了 <code>FLAG_PRESENT | FLAG_WRITABLE</code>，没有 <code>FLAG_USER</code>：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 原始代码——两处都是这样</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">entry.raw </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> new_page </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_PRESENT </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_WRITABLE;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>所以即使用户态映射请求带了 FLAG_USER（最终 PT 条目有 FLAG_USER），中间的 PML4/PDPT/PD 条目都没有 FLAG_USER。CPU 在第一级检查就拒绝了 Ring 3 的访问。</p><h3 id="修复-2" tabindex="-1">修复 <a class="header-anchor" href="#修复-2" aria-label="Permalink to &quot;修复&quot;">​</a></h3><p>给 walk_level 增加 <code>user_flag</code> 参数，从 VMM::map() 中提取 <code>flags &amp; FLAG_USER</code> 并传递给每一级：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_flag </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> flags </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_USER;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pdpt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> walk_level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(pml4_table, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PML4_INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(virt), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, user_flag);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pd   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> walk_level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(pdpt, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PDPT_INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(virt), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, user_flag);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pt   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> walk_level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(pd, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PD_INDEX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(virt), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, user_flag);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>walk_level 内部分配新页表时加上 user_flag：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">entry.raw </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> new_page </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_PRESENT </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FLAG_WRITABLE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_flag;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样，如果 map() 的 flags 包含 FLAG_USER，每一级页表项都会有 user 位。内核态映射不受影响——不传 FLAG_USER，user_flag = 0。</p><h3 id="教训-2" tabindex="-1">教训 <a class="header-anchor" href="#教训-2" aria-label="Permalink to &quot;教训&quot;">​</a></h3><p>x86-64 的页表权限是逐级检查的，任何一级缺权限都会拒绝访问。这不是什么冷门知识点——Intel SDM Vol.3A Section 4.6 写得很清楚——但很容易被忽略，因为大多数简单的页表教程只关注最终 PT 条目的权限位，很少强调中间级别的权限传播。</p><h2 id="设计对比-页表权限传播的不同实现" tabindex="-1">设计对比：页表权限传播的不同实现 <a class="header-anchor" href="#设计对比-页表权限传播的不同实现" aria-label="Permalink to &quot;设计对比：页表权限传播的不同实现&quot;">​</a></h2><p>Linux 的页表映射路径（<code>__apply_to_page_range</code> 及相关函数）在分配中间页表时使用了 <code>pgtable_ops</code> 回调，其中包含权限传播逻辑。Linux 的 pte allocator 会根据最终的权限位设置中间页表的权限——本质上和 Cinux 的 <code>user_flag</code> 参数做的是同一件事，但 Linux 的实现更通用（通过函数指针而不是直接参数）。</p><p>xv6 是 32 位，只有两级页表（PD + PT），而且 xv6 的用户页直接使用 <code>mappages()</code> 函数，该函数在分配 PD 条目时没有显式传播 user 位——但 32 位 x86 的权限检查比 64 位宽松，而且 xv6 的 setupkvm() 在创建用户页表时直接从模板复制，不走 walk_level 这种通用路径。所以 xv6 没有遇到这个问题。</p><p>SerenityOS 使用了自己的 PageDirectory/PageTable 类层次结构，每个级别有自己的 allocate/reallocate 方法，权限传播是在类方法中处理的——比 Cinux 的过程式 walk_level 更面向对象，但核心机制相同。</p><h2 id="三个-bug-的共性" tabindex="-1">三个 Bug 的共性 <a class="header-anchor" href="#三个-bug-的共性" aria-label="Permalink to &quot;三个 Bug 的共性&quot;">​</a></h2><p>虽然这三个 Bug 涉及不同的子系统（页表、MSR、VMM），但它们有一个共同的主题：<strong>x86-64 的权限检查是多层的，每一层都必须正确配置</strong>。</p><ul><li>Bug 1（identity mapping 丢失）：地址空间切换时没有正确继承低半区映射——页表层级问题</li><li>Bug 2（STAR MSR 移位错误）：MSR 写入只看 32 位 EDX 而非 64 位 RDX——寄存器宽度问题</li><li>Bug 3（缺 FLAG_USER）：页表权限必须逐级传播——权限层级问题</li></ul><p>这三者都是&quot;x86-64 的某个检查是逐级/逐位进行的，而非只看最终结果&quot;。这应该是你在写 OS 内核时需要牢记的核心原则：不要假设&quot;最终结果对了就行&quot;——x86-64 会检查路径上的每一个中间步骤。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>三个 bug 全部修复后，Ring 3 终于能正确启动了。串口输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[USER] User address space activated (PML4 at phys 0x000000000106D000).</span></span>
<span class="line"><span>[USER] Jumping to Ring 3: entry=0x400000 stack=0x7FFFFF000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>==== EXCEPTION: #GP (vector 13) ====</span></span>
<span class="line"><span>  RIP   = 0x0000000000400000   CS  = 0x001b</span></span>
<span class="line"><span>[EXCEPTION] #GP at RIP=0x400000 from user mode (Ring 3)</span></span>
<span class="line"><span>[EXCEPTION] Privileged instruction executed in Ring 3 -- protection works!</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>CS=0x33（User64 代码段 Ring 3），RIP=0x400000（用户程序入口），用户程序执行 <code>cli</code> 触发 #GP。特权隔离验证成功。虽然过程曲折，但最终结果是对的——这三个 bug 让我们对 x86-64 特权级切换的每一个细节都有了更深的理解。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM: Vol.3A Section 4.6 — Access Rights, U/S bit in paging structures</li><li>Intel SDM: Vol.2A WRMSR/RDMSR — MSR 读写指令只操作 EDX:EAX</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Getting_to_Ring_3" target="_blank" rel="noreferrer">Getting to Ring 3</a></li><li>Cinux notes: document/notes/022/001_usermode_three_bugs.md</li><li>Cinux notes: document/notes/022/002_sfmask_qemu_msr.md</li></ul>`,73)])])}const E=a(t,[["render",l]]);export{g as __pageData,E as default};
